/* =============================================================
   E-LaptopShop — Seed data (1303 products from Kaggle dataset)
   Source: laptop_price.csv
   Run AFTER 01_schema_current.sql
   ============================================================= */
SET NOCOUNT ON;
SET XACT_ABORT ON;
GO

/* ---------- Brands ---------- */
IF NOT EXISTS (SELECT 1 FROM dbo.Brands)
BEGIN
    SET IDENTITY_INSERT dbo.Brands ON;
    SET IDENTITY_INSERT dbo.Brands OFF;
END
GO

/* ---------- Categories ---------- */
IF NOT EXISTS (SELECT 1 FROM dbo.Categories)
BEGIN
    SET IDENTITY_INSERT dbo.Categories ON;
    SET IDENTITY_INSERT dbo.Categories OFF;
END
GO

/* ---------- Products (1303 rows) ---------- */
IF NOT EXISTS (SELECT 1 FROM dbo.Products)
BEGIN
    SET IDENTITY_INSERT dbo.Products ON;
    SET IDENTITY_INSERT dbo.Products OFF;
END
GO

/* ---------- ProductSpecifications (1303 rows) ---------- */
IF NOT EXISTS (SELECT 1 FROM dbo.ProductSpecifications)
BEGIN
END
GO

/* ---------- Inventories (1 record/product) ---------- */
IF NOT EXISTS (SELECT 1 FROM dbo.Inventories)
BEGIN
END
GO

PRINT N'>>> Seed completed: 19 Brands, 6 Categories, 1303 Products, 1303 Specs, 1303 Inventory rows';
